const STORY_MUSIC_SRC = 'assets/intro-theme.mp3';
const INITIAL_REPLAY_SHARE_ID = (() => {
  try {
    return String(new URL(window.location.href).searchParams.get('replay') || '').trim();
  } catch (error) {
    return '';
  }
})();

function isReplayUrlView() {
  return !!INITIAL_REPLAY_SHARE_ID;
}
const STORY_MUSIC_START_SECONDS = 0;
const STORY_MUSIC_VOLUME = 0.2;
let storyMusic = null;
let storyMusicVolume = STORY_MUSIC_VOLUME;
let storyMusicMuted = false;
let storyMusicStarted = false;


function tryStartMusic() {
  const audio = ensureStoryMusic();
  if (!audio) return Promise.resolve(false);
  try { if (audio.currentTime < STORY_MUSIC_START_SECONDS) audio.currentTime = STORY_MUSIC_START_SECONDS; } catch (error) {}
  const attempt = () => {
    try {
      const playResult = audio.play();
      if (playResult && typeof playResult.then === 'function') {
        return playResult.then(() => true).catch(() => false);
      }
      return Promise.resolve(true);
    } catch (error) {
      return Promise.resolve(false);
    }
  };
  return attempt().then((started) => {
    if (started) return true;
    const retryOnce = () => {
      attempt().finally(() => {
        window.removeEventListener('pointerdown', retryOnce, true);
        window.removeEventListener('keydown', retryOnce, true);
        window.removeEventListener('touchstart', retryOnce, true);
        document.removeEventListener('visibilitychange', retryWhenVisible, true);
      });
    };
    const retryWhenVisible = () => { if (!document.hidden) retryOnce(); };
    window.addEventListener('pointerdown', retryOnce, true);
    window.addEventListener('keydown', retryOnce, true);
    window.addEventListener('touchstart', retryOnce, true);
    document.addEventListener('visibilitychange', retryWhenVisible, true);
    return false;
  });
}

function ensureStoryMusic() {
  if (storyMusic) return storyMusic;
  try {
    storyMusic = new Audio(STORY_MUSIC_SRC);
    storyMusic.preload = 'auto';
    storyMusic.volume = storyMusicMuted ? 0 : storyMusicVolume;
  } catch (error) {
    storyMusic = null;
  }
  return storyMusic;
}

function applyStoryMusicVolume() {
  const audio = ensureStoryMusic();
  if (!audio) return;
  try {
    audio.volume = storyMusicMuted ? 0 : storyMusicVolume;
  } catch (error) {}
}

function stopStoryMusic() {
  const audio = ensureStoryMusic();
  if (!audio) return;
  try {
    audio.pause();
    audio.currentTime = STORY_MUSIC_START_SECONDS;
    storyMusicStarted = false;
  } catch (error) {}
}

function startStoryMusic() {
  const audio = ensureStoryMusic();
  if (!audio) return Promise.resolve(false);
  try {
    audio.pause();
    if (!Number.isFinite(audio.currentTime) || Math.abs(audio.currentTime - STORY_MUSIC_START_SECONDS) > 0.5) {
      audio.currentTime = STORY_MUSIC_START_SECONDS;
    }
    const targetVolume = storyMusicMuted ? 0 : storyMusicVolume;
    try { audio.volume = 0; } catch (error) {}
    return audio.play().then(() => {
      storyMusicStarted = true;
      const fadeSteps = 16;
      const fadeMs = 800;
      let fadeStep = 0;
      const fadeTimer = setInterval(() => {
        fadeStep += 1;
        try {
          const liveTargetVolume = storyMusicMuted ? 0 : storyMusicVolume;
          audio.volume = Math.max(0, Math.min(1, liveTargetVolume * (fadeStep / fadeSteps)));
        } catch (error) {}
        if (fadeStep >= fadeSteps) {
          clearInterval(fadeTimer);
          applyStoryMusicVolume();
        }
      }, Math.round(fadeMs / fadeSteps));
      return true;
    }).catch(() => false);
  } catch (error) {
    return Promise.resolve(false);
  }
}


function renderStoryScreen(textEl, screen) {
  if (!textEl) return;
  const rawText = String(screen && screen.text ? screen.text : '');
  const safeText = rawText.replace(/\|/g, ' ');
  textEl.classList.remove('story-text-staggered', 'fiery-final');
  if (screen && screen.fieryFinal) {
    const subtitle = String(screen.subtitle || '').trim();
    const escapedTitle = safeText
      .replace(/&/g, '&amp;')
      .replace(/</g, '&lt;')
      .replace(/>/g, '&gt;');
    const escapedSubtitle = subtitle
      .replace(/&/g, '&amp;')
      .replace(/</g, '&lt;')
      .replace(/>/g, '&gt;');
    textEl.classList.add('fiery-final');
    textEl.innerHTML = `
      <div class="story-final-title-wrap">
        <div class="story-final-title" aria-label="${escapedTitle}">${escapedTitle}</div>
        <div class="story-final-subtitle">${escapedSubtitle}</div>
      </div>
    `;
    return;
  }
  textEl.textContent = safeText;
}


function playStorySequence() {
  const overlay = document.getElementById('storyOverlay');
  const textEl = document.getElementById('storyText');
  const skipBtn = document.getElementById('storySkipBtn');
  const prevBtn = document.getElementById('storyPrevBtn');
  const nextBtn = document.getElementById('storyNextBtn');
  const muteBtn = document.getElementById('storyMuteBtn');
  const volumeSlider = document.getElementById('storyVolumeSlider');
  const volumeValue = document.getElementById('storyVolumeValue');
  const controlsEl = overlay ? overlay.querySelector('.story-controls') : null;
  if (!overlay || !textEl) return;

  let storyControlsActiveTimer = null;
  function pulseStoryControls() {
    if (!controlsEl) return;
    controlsEl.classList.add('story-controls-active');
    if (storyControlsActiveTimer) clearTimeout(storyControlsActiveTimer);
    storyControlsActiveTimer = setTimeout(() => {
      controlsEl.classList.remove('story-controls-active');
      storyControlsActiveTimer = null;
    }, 100);
  }

  let index = 0;
  let cancelled = false;
  let activeTimers = [];

  function clearStoryTimers() {
    for (const id of activeTimers) clearTimeout(id);
    activeTimers = [];
  }

  function queue(fn, ms) {
    const id = setTimeout(fn, ms);
    activeTimers.push(id);
    return id;
  }

  function syncStoryMusicControls() {
    if (volumeSlider) volumeSlider.value = String(Math.round(storyMusicVolume * 100));
    if (volumeValue) volumeValue.textContent = `${Math.round(storyMusicMuted ? 0 : storyMusicVolume * 100)}%`;
    if (muteBtn) muteBtn.textContent = storyMusicMuted ? 'Unmute Music' : 'Silence Music';
  }

  function syncStoryNavControls() {
    if (prevBtn) prevBtn.disabled = index <= 0;
    if (nextBtn) nextBtn.textContent = index >= STORY_SCREENS.length - 1 ? 'Finish' : 'Next';
  }

  function tryStartMusic(forceRestart = false) {
    const audio = ensureStoryMusic();
    if (!audio) return;
    if (!forceRestart && storyMusicStarted && !audio.paused) return;
    startStoryMusic();
  }

  function finishStory() {
    if (cancelled) return;
    cancelled = true;
    clearStoryTimers();

    const audio = ensureStoryMusic();
    const startingVolume = audio ? Number(audio.volume || 0) : 0;
    let fadeStep = 0;
    const fadeSteps = 18;
    const fadeMs = 900;

    try {
      overlay.style.transition = 'opacity 900ms ease';
      overlay.style.opacity = '0';
    } catch (error) {}

    try {
      textEl.style.transition = 'opacity 900ms ease, transform 900ms ease';
      textEl.style.opacity = '0';
    } catch (error) {}

    const fadeTimer = setInterval(() => {
      fadeStep += 1;
      if (audio) {
        try {
          audio.volume = Math.max(0, startingVolume * (1 - (fadeStep / fadeSteps)));
        } catch (error) {}
      }
      if (fadeStep >= fadeSteps) {
        clearInterval(fadeTimer);
        stopStoryMusic();
        textEl.classList.remove('visible');
        overlay.classList.add('hidden');
        try {
          document.body.classList.remove('intro-open');
          document.body.classList.remove('story-active');
          if (typeof syncStatusOverlayVisibility === 'function') syncStatusOverlayVisibility(true);
        } catch (error) {}
        try {
          overlay.style.opacity = '';
          textEl.style.opacity = '';
        } catch (error) {}
        try {
          if (typeof window !== 'undefined') window.__dfkIntroHasPlayed = true;
        } catch (error) {}
        try {
          if (typeof window !== 'undefined' && typeof window.DFKRevealHowToPlayAfterStory === 'function') {
            window.DFKRevealHowToPlayAfterStory();
          } else if (typeof window !== 'undefined' && typeof window.DFKOpenHowToPlay === 'function') {
            window.DFKOpenHowToPlay();
          } else {
            if (typeof setBoardInputLocked === 'function') setBoardInputLocked(false);
            if (typeof syncStatusOverlayVisibility === 'function') syncStatusOverlayVisibility(false);
            if (typeof showStatusOverlay === 'function') showStatusOverlay();
          }
        } catch (error) {
          try { if (typeof window !== 'undefined' && typeof window.DFKOpenHowToPlay === 'function') window.DFKOpenHowToPlay(); } catch (_error) { try { if (typeof setBoardInputLocked === 'function') setBoardInputLocked(false); } catch (__error) {} }
        }
      }
    }, Math.round(fadeMs / fadeSteps));
  }

  function renderCurrentScreen() {
    if (cancelled) return;
    clearStoryTimers();
    const screen = STORY_SCREENS[Math.max(0, Math.min(STORY_SCREENS.length - 1, index))];
    try { const oldBtn = document.getElementById('introPlayBtn'); if (oldBtn) oldBtn.remove(); } catch (error) {}
    renderStoryScreen(textEl, screen);

    try {
      if (screen && screen.text === 'DFK DEFENDER') {
        textEl.classList.add('big-final');
      } else {
        textEl.classList.remove('big-final');
      }
      if (screen && screen.fieryFinal) {
        textEl.classList.add('fiery-final');
      } else {
        textEl.classList.remove('fiery-final');
      }
    } catch (error) {}

    try {
      if (screen && screen.noAnim) {
        textEl.style.animation = 'none';
        textEl.style.transition = 'opacity 600ms ease, transform 600ms ease';
        textEl.style.opacity = '1';
        textEl.style.transform = screen && screen.fieryFinal ? 'scale(1.01)' : 'scale(1)';
      } else {
        textEl.style.animation = '';
        textEl.style.transition = '';
        textEl.style.opacity = '';
        textEl.style.transform = '';
      }
    } catch (error) {}

    try {
      if (screen && screen.text === 'We weren’t fighting the darkness, we were feeding it') {
        textEl.classList.add('story-one-line');
      } else {
        textEl.classList.remove('story-one-line');
      }
    } catch (error) {}

    textEl.style.setProperty('--story-frame-duration', `${screen.duration}ms`);
    textEl.classList.remove('visible');
    void textEl.offsetWidth;

    if (screen && screen.noAnim) {
      textEl.style.animation = 'none';
      textEl.style.opacity = '1';
      textEl.style.transform = screen && screen.fieryFinal ? 'scale(1.01)' : 'scale(1)';
      if (screen && screen.fieryFinal) {
        let zoomStep = 0;
        const zoomMax = 0.16;
        const zoomTickMs = 140;
        const approxDuration = Math.max(1, Number((ensureStoryMusic() && ensureStoryMusic().duration) || 45) - STORY_MUSIC_START_SECONDS);
        const totalTicks = Math.max(1, Math.round((approxDuration * 1000) / zoomTickMs));
        const zoomFrame = () => {
          if (cancelled || index !== STORY_SCREENS.length - 1) return;
          zoomStep += 1;
          const zoomRatio = Math.min(1, zoomStep / totalTicks);
          const scale = 1.01 + (zoomMax * zoomRatio);
          try { textEl.style.transform = `scale(${scale.toFixed(4)})`; } catch (error) {}
          queue(zoomFrame, zoomTickMs);
        };
        queue(zoomFrame, zoomTickMs);
      }
    } else {
      textEl.classList.add('visible');
    }

    syncStoryNavControls();
  }

  overlay.classList.remove('hidden');
  syncStoryMusicControls();
  syncStoryNavControls();
  Promise.resolve().then(() => tryStartMusic(true));

  if (skipBtn) {
    skipBtn.onclick = () => { pulseStoryControls(); finishStory(); };
  }
  if (prevBtn) {
    prevBtn.onclick = () => {
      pulseStoryControls();
      if (index > 0) {
        index -= 1;
        renderCurrentScreen();
      }
    };
  }
  if (nextBtn) {
    nextBtn.onclick = () => {
      pulseStoryControls();
      if (index >= STORY_SCREENS.length - 1) {
        finishStory();
        return;
      }
      index += 1;
      renderCurrentScreen();
    };
  }
  if (muteBtn) {
    muteBtn.onclick = () => {
      pulseStoryControls();
      storyMusicMuted = !storyMusicMuted;
      applyStoryMusicVolume();
      syncStoryMusicControls();
      if (!storyMusicMuted) tryStartMusic();
    };
  }
  if (volumeSlider) {
    const onVolumeInput = () => {
      const nextValue = Number(volumeSlider.value);
      if (Number.isFinite(nextValue)) {
        pulseStoryControls();
        storyMusicVolume = Math.min(1, Math.max(0, nextValue / 100));
        if (storyMusicVolume > 0 && storyMusicMuted) storyMusicMuted = false;
        applyStoryMusicVolume();
        syncStoryMusicControls();
        tryStartMusic();
      }
    };
    volumeSlider.oninput = onVolumeInput;
    volumeSlider.onchange = onVolumeInput;
    volumeSlider.addEventListener('pointerdown', pulseStoryControls, { passive: true });
    volumeSlider.addEventListener('touchstart', pulseStoryControls, { passive: true });
    volumeSlider.addEventListener('focus', pulseStoryControls);
  }
  [muteBtn, skipBtn, prevBtn, nextBtn].forEach((btn) => {
    if (!btn) return;
    btn.addEventListener('pointerdown', pulseStoryControls, { passive: true });
    btn.addEventListener('touchstart', pulseStoryControls, { passive: true });
    btn.addEventListener('focus', pulseStoryControls);
  });

  document.addEventListener('keydown', function onStoryKey(event) {
    if (cancelled) {
      document.removeEventListener('keydown', onStoryKey);
      return;
    }
    if (event.key === 'Escape') {
      finishStory();
    } else if (event.key === 'ArrowRight' || event.key === ' ' || event.key === 'Enter') {
      event.preventDefault();
      if (index >= STORY_SCREENS.length - 1) finishStory();
      else {
        index += 1;
        renderCurrentScreen();
      }
    } else if (event.key === 'ArrowLeft') {
      event.preventDefault();
      if (index > 0) {
        index -= 1;
        renderCurrentScreen();
      }
    }
  });

  overlay.addEventListener('click', (event) => {
    if (!cancelled) tryStartMusic();
    if (event.target === overlay) finishStory();
  });

  document.addEventListener('pointerdown', function onInitialStoryPointer() {
    if (!cancelled) tryStartMusic();
    if (cancelled || storyMusicStarted) {
      document.removeEventListener('pointerdown', onInitialStoryPointer, true);
    }
  }, true);

  renderCurrentScreen();
}

window.addEventListener('load', () => {
  if (isReplayUrlView()) {
    try { document.body.classList.remove('intro-open'); document.body.classList.remove('story-active'); } catch (error) {}
    return;
  }
  try { if (!window.__dfkModeChoiceMade) document.body.classList.add('intro-open'); } catch (error) {}
});


