    free: Object.freeze(['waves_100', 'kill_50', 'small_40', 'medium_20', 'large_8', 'skitter_5', 'boss_1', 'damage_10k', 'gold_800', 'spend_600', 'relics_1', 'heroes_3', 'upgrades_4', 'satellites_1', 'waves_10', 'wave_peak_10']),
