  function openMilestonePaymentChoiceModal(heroType) {
    const offer = game.milestoneHeroOffer;
    const template = TOWER_TEMPLATES[heroType];
    if (!offer || !template) return;
    const modal = ensureMilestonePaymentChoiceModalElements();
    const body = modal.querySelector('#milestonePaymentChoiceBody');
    const actions = modal.querySelector('#milestonePaymentChoiceActions');
    if (!body || !actions) return;
    const useAvax = canUseAvaxRailsPurchases();
    const goldAvailable = false;
    const jewelWei = getMilestoneHeroJewelPriceWei(offer);
    const jewelLabel = getMilestoneHeroJewelPriceLabel(offer);
    const avaxLabel = formatAvaxValue(AVAX_MILESTONE_HERO_WEI);
    const jewelAvailable = isConnectedWalletOnDfk() && hasWalletJewelForWei(jewelWei);
    const honkLabel = getMilestoneHeroHonkPriceLabel(offer);
    const honkAvailable = isConnectedWalletOnDfk() && getWalletHonkBalance() + 1e-9 >= getHonkPurchaseAmountFromJewel(DFK_EXTRA_HERO_JEWEL_COST);
    body.innerHTML = `<p>Hire ${template.name} L${offer.heroLevel}. Choose how you want to pay.</p>
      <p>${useAvax ? avaxLabel : `${jewelLabel} or ${honkLabel}` }.</p>`;
    actions.innerHTML = '';
    if (useAvax) {
      const avaxBtn = document.createElement('button');
      avaxBtn.type = 'button';
      avaxBtn.className = 'small-action milestone-hero-offer-btn';
      avaxBtn.textContent = `Use ${avaxLabel}`;
      avaxBtn.addEventListener('click', () => {
        setMilestonePaymentChoiceProcessing(template.name);
        beginMilestoneHeroHireAvax(heroType, { preserveModal: true }).catch((error) => console.error(error));
      });
      actions.appendChild(avaxBtn);
    }
    if (jewelAvailable) {
      const jewelBtn = document.createElement('button');
      jewelBtn.type = 'button';
      jewelBtn.className = 'small-action milestone-hero-offer-btn';
      jewelBtn.textContent = `Use ${jewelLabel}`;
      jewelBtn.addEventListener('click', () => {
        setMilestonePaymentChoiceProcessing(template.name);
        beginMilestoneHeroHireJewel(heroType, { preserveModal: true }).catch((error) => console.error(error));
      });
      actions.appendChild(jewelBtn);
    }
    if (!useAvax && honkAvailable) {
      const honkBtn = document.createElement('button');
      honkBtn.type = 'button';
      honkBtn.className = 'small-action milestone-hero-offer-btn';
      honkBtn.textContent = `Use ${honkLabel}`;
      honkBtn.addEventListener('click', () => {
        setMilestonePaymentChoiceProcessing(template.name);
        beginMilestoneHeroHireHonk(heroType, { preserveModal: true }).catch((error) => console.error(error));
      });
      actions.appendChild(honkBtn);
    }
    const cancelBtn = document.createElement('button');
    cancelBtn.type = 'button';
    cancelBtn.className = 'secondary small-action milestone-hero-offer-btn';
    cancelBtn.textContent = 'Cancel';
    cancelBtn.addEventListener('click', () => {
      modal.classList.add('hidden');
      modal.setAttribute('aria-hidden', 'true');
    });
    actions.appendChild(cancelBtn);
    modal.classList.remove('hidden');
    modal.setAttribute('aria-hidden', 'false');
  }

  async function beginMilestoneHeroHireFlow(heroType) {
    const offer = game.milestoneHeroOffer;
    if (!offer) return;
    if (canUseAvaxRailsPurchases()) {
      return beginMilestoneHeroHireAvax(heroType);
    }
    const goldAvailable = false;
    const jewelAvailable = isConnectedWalletOnDfk() && hasWalletJewelForWei(getMilestoneHeroJewelPriceWei(offer));
    const honkAvailable = isConnectedWalletOnDfk() && getWalletHonkBalance() + 1e-9 >= getHonkPurchaseAmountFromJewel(DFK_EXTRA_HERO_JEWEL_COST);
    if ([goldAvailable, jewelAvailable, honkAvailable].filter(Boolean).length > 1) {
      openMilestonePaymentChoiceModal(heroType);
      return;
    }
    if (jewelAvailable) {
      return beginMilestoneHeroHireJewel(heroType);
    }
    if (honkAvailable) {
      return beginMilestoneHeroHireHonk(heroType);
    }
    showBanner('Need 2 JEWEL or HONK equivalent on DFK Chain to hire this hero.', 2400);
    return null;
  }


  

  

  function queueMilestoneReinforcement(heroType, offer, txHash = '') {
    const template = TOWER_TEMPLATES[heroType];
    if (!offer || !template) return null;
    game.pendingMilestoneHeroPlacement = {
      wave: offer.wave,
      heroType,
      heroLevel: offer.heroLevel,
      burnCost: 0,
      txHash: String(txHash || ''),
      queuedAt: Date.now(),
    };
    game.placingHeroType = null;
    game.placingHeroCost = 0;
    game.placingHeroUsesBonus = false;
    game.placingSatelliteSourceId = null;
    game.placingWalletHeroId = null;
    setInstruction(`Your ${template.name} reinforcement is ready in the Hire menu now. Place it whenever you are ready.`);
    render();
    return game.pendingMilestoneHeroPlacement;
  }

  function showHeroPlacementReminder(heroLabel) {
    if (!els.heroPlacementReminderModal || !els.heroPlacementReminderBody) return;
    els.heroPlacementReminderBody.innerHTML = `<p>Place your ${heroLabel} on the gameboard.</p><p>If you closed the purchase window, your hero is already waiting in the Hire menu now.</p>`;
    els.heroPlacementReminderModal.classList.remove('hidden');
    els.heroPlacementReminderModal.setAttribute('aria-hidden', 'false');
  }

  function getAvailableUnplacedHeroLabels() {
    const labels = [];
    if (game.pendingMilestoneHeroPlacement && game.pendingMilestoneHeroPlacement.heroType) {
      const template = TOWER_TEMPLATES[game.pendingMilestoneHeroPlacement.heroType];
      if (template) labels.push(template.name);
    }
    if (!game.pendingMilestoneHeroPlacement && Number(game.bonusHeroHireCharges || 0) > 0) {
      labels.push(`${Math.max(0, Number(game.bonusHeroHireCharges || 0))} extra hero${Number(game.bonusHeroHireCharges || 0) === 1 ? '' : 'es'}`);
    }
    return labels;
  }

  function maybeShowUnplacedHeroReminder(force = false) {
    const labels = getAvailableUnplacedHeroLabels();
    const wave = Math.max(0, Number(game.waveNumber || 0));
    if (!labels.length) return;
    if (!force) {
      if (wave <= 0 || wave % 5 !== 0 || game.lastHeroPlacementReminderWave === wave) return;
      game.lastHeroPlacementReminderWave = wave;
    }
    showHeroPlacementReminder(labels[0]);
  }

  function setMilestoneOfferTxnPending(label = '') {
    game.milestoneOfferTxnPending = true;
    game.milestoneOfferTxnLabel = String(label || '').trim();
    render();
  }

  function clearMilestoneOfferTxnPending() {
    game.milestoneOfferTxnPending = false;
    game.milestoneOfferTxnLabel = '';
    render();
  }

  function renderMilestoneHeroOffer() {
    const modal = els.milestoneHeroOfferModal;
    const body = els.milestoneHeroOfferBody;
    const actions = els.milestoneHeroOfferActions;
    const title = els.milestoneHeroOfferTitle;
    if (!modal || !body || !actions || !title) return;
    const heroOffer = game.milestoneHeroOffer;
    const barrierOffer = game.milestoneBarrierOffer;
    if (!heroOffer && !barrierOffer) {
      modal.classList.add('hidden');
      return;
    }
    game.countdownMs = 0;
    game.autoStartReadyAt = 0;
    if (!game.runningWave && game.phase === SETUP_PHASES.BATTLE && els.startWaveBtn) {
      els.startWaveBtn.disabled = true;
    }
    const useAvax = canUseAvaxRailsPurchases();
    const walletDfkgold = getWalletDfkgoldBalance();
    const hasWallet = !!getConnectedWalletAddress();
    const jewelLabel = heroOffer ? getMilestoneHeroJewelPriceLabel(heroOffer) : '';
    const avaxHeroLabel = heroOffer ? formatAvaxValue(AVAX_MILESTONE_HERO_WEI) : '';
    const jewelAvailable = !!(heroOffer && isConnectedWalletOnDfk() && hasWalletJewelForWei(getMilestoneHeroJewelPriceWei(heroOffer)));
    const honkLabel = heroOffer ? getMilestoneHeroHonkPriceLabel(heroOffer) : '';
    const honkAvailable = !!(heroOffer && isConnectedWalletOnDfk() && getWalletHonkBalance() + 1e-9 >= getHonkPurchaseAmountFromJewel(DFK_EXTRA_HERO_JEWEL_COST));
    const shouldAutoRefreshMilestoneWallet = !!(heroOffer && hasWallet && !useAvax && isConnectedWalletOnDfk());
    const now = Date.now();
    if (shouldAutoRefreshMilestoneWallet && !game.milestoneOfferAutoRefreshPending && (now - Number(game.milestoneOfferLastAutoRefreshAt || 0) >= 15000)) {
      game.milestoneOfferAutoRefreshPending = true;
      game.milestoneOfferLastAutoRefreshAt = now;
      refreshWalletJewelTokenBalance({ skipMilestoneRender: true }).catch(() => {}).finally(() => {
        game.milestoneOfferAutoRefreshPending = false;
      });
    }
    const sections = [];
    const milestoneTxnPending = !!game.milestoneOfferTxnPending;
    title.textContent = heroOffer ? `Reinforcements at Wave ${heroOffer.wave}` : `Barrier Bundle at Wave ${barrierOffer.wave}`;
    if (heroOffer) {
      sections.push(`<p>You survived long enough for help to arrive. One time offer to hire a new hero of your choice for ${useAvax ? avaxHeroLabel : `${jewelLabel} or ${honkLabel}` }.</p><p>The hired hero arrives at level ${heroOffer.heroLevel} after the payment is confirmed. After confirming the TX this pop up will disappear, click anywhere on the board to place your new hired hero. They can be moved after placement. If you forget to place them they will appear in the hero hire menu to be placed later for free.</p>`);
    }
    if (barrierOffer) {
      const barrierLabel = useAvax ? formatAvaxValue(AVAX_MILESTONE_BARRIER_WEI) : `${barrierOffer.burnCost.toLocaleString()} DFK Gold`;
      sections.push(`<p>Need more room to build? One time offer to buy ${barrierOffer.barrierCount} more barriers for ${barrierLabel}.</p><p>If you buy them now, the next wave waits while you place the extra barriers.</p>`);
    }
    body.innerHTML = sections.join('');
    actions.innerHTML = '';
    if (heroOffer) {
      const heroTypes = ['warrior', 'archer', 'wizard', 'seer', 'priest', 'pirate', 'monk', 'berserker'];
      const goldAvailable = false;
      const canLaunchHire = hasWallet && (useAvax || goldAvailable || jewelAvailable || honkAvailable);
      for (const type of heroTypes) {
        const t = TOWER_TEMPLATES[type];
        const currentTypeCount = (game.towers || []).filter((tower) => tower && tower.type === type && tower.hp > 0 && !tower.isSatellite && !tower.isChampion).length;
        const btn = document.createElement('button');
        btn.type = 'button';
        btn.className = 'small-action milestone-hero-offer-btn';
        btn.textContent = milestoneTxnPending ? 'Submitting…' : ((game.dfkGoldSwapPending || game.jewelTradePending) ? 'Waiting…' : `${t.name} L${heroOffer.heroLevel}`);
        btn.disabled = milestoneTxnPending || !canLaunchHire || game.dfkGoldSwapPending || game.jewelTradePending || (type === 'monk' && currentTypeCount >= 2);
        btn.title = '';
        btn.addEventListener('click', () => {
          beginMilestoneHeroHireFlow(type).catch((error) => console.error(error));
        });
        actions.appendChild(btn);
      }
      const note = document.createElement('div');
      note.className = 'milestone-hero-offer-note';
      const nativeBalanceLabel = getWalletNativeJewelBalanceLabel();
      const balanceSummary = useAvax
        ? `Wallet: ${nativeBalanceLabel}`
        : `Wallet: ${nativeBalanceLabel} · HONK: ${getWalletHonkBalanceLabel()}`;
      if (!hasWallet) note.textContent = useAvax ? 'Connect a wallet on Avalanche to pay with AVAX for this hire.' : 'Connect a wallet on DFK Chain to pay with JEWEL or HONK for this hire.';
      else if (milestoneTxnPending) note.textContent = `${game.milestoneOfferTxnLabel || 'Purchase'} submitting…`;
      else if (game.dfkGoldSwapPending || game.jewelTradePending) note.textContent = 'Waiting for wallet confirmation…';
      else if (useAvax) note.textContent = `Pick a hero to pay ${avaxHeroLabel} with AVAX for the hire. ${balanceSummary}`;
      else if ([goldAvailable, jewelAvailable, honkAvailable].filter(Boolean).length > 1) note.textContent = `Multiple payment methods are available. Pick a hero and the lightwindow will ask: JEWEL or HONK. ${balanceSummary}`;
      else if (jewelAvailable) note.textContent = `Only JEWEL is ready right now, so picking a hero launches the JEWEL transaction. ${balanceSummary}`;
      else if (honkAvailable) note.textContent = `Only HONK is ready right now, so picking a hero launches the HONK transaction. ${balanceSummary}`;
      else note.textContent = `Need ${jewelLabel} or ${honkLabel} in the connected wallet. ${balanceSummary}`;
      actions.appendChild(note);

      if (hasWallet) {
        const refreshBtn = document.createElement('button');
        refreshBtn.type = 'button';
        refreshBtn.className = 'secondary small-action milestone-hero-offer-btn';
        refreshBtn.textContent = milestoneTxnPending ? 'Submitting…' : (game.milestoneOfferWalletRefreshPending ? 'Refreshing…' : 'Refresh Wallet');
        refreshBtn.disabled = milestoneTxnPending || !!game.milestoneOfferWalletRefreshPending;
        refreshBtn.addEventListener('click', async () => {
          if (game.milestoneOfferWalletRefreshPending) return;
          game.milestoneOfferWalletRefreshPending = true;
          renderMilestoneHeroOffer();
          try {
            await refreshWalletEconomyDetails();
            if (!useAvax) {
              await refreshWalletJewelTokenBalance();
              await recoverPendingMilestoneJewelHire().catch(() => false);
            }
          } finally {
            game.milestoneOfferWalletRefreshPending = false;
            renderMilestoneHeroOffer();
          }
        });
        actions.appendChild(refreshBtn);

        if (game.pendingMilestonePurchase && game.pendingMilestonePurchase.kind === 'jewel_milestone_hero_hire') {
          const cancelStuckBtn = document.createElement('button');
          cancelStuckBtn.type = 'button';
          cancelStuckBtn.className = 'secondary small-action milestone-hero-offer-btn';
          cancelStuckBtn.textContent = milestoneTxnPending ? 'Submitting…' : 'Clear Stuck Waiting';
          cancelStuckBtn.disabled = milestoneTxnPending || !!game.milestoneOfferWalletRefreshPending;
          cancelStuckBtn.addEventListener('click', () => {
            game.jewelTradePending = false;
            clearPendingMilestonePurchase();
            showBanner('Cleared the stuck waiting state. No hero was granted.', 2600);
            renderMilestoneHeroOffer();
            updateJewelTradeUi();
            updateRelicSwapUi();
          });
          actions.appendChild(cancelStuckBtn);
        }
      }
    }
    if (barrierOffer) {
      const barrierBtn = document.createElement('button');
      barrierBtn.type = 'button';
      barrierBtn.className = 'small-action milestone-hero-offer-btn';
      barrierBtn.textContent = milestoneTxnPending ? 'Submitting…' : (game.dfkGoldSwapPending ? 'Waiting…' : `Buy ${barrierOffer.barrierCount} More Barriers`);
      barrierBtn.disabled = milestoneTxnPending || game.dfkGoldSwapPending || !hasWallet || (!useAvax && walletDfkgold < barrierOffer.burnCost);
      barrierBtn.addEventListener('click', () => {
        (useAvax ? beginMilestoneBarrierOfferAvax() : beginMilestoneBarrierOffer()).catch((error) => console.error(error));
      });
      actions.appendChild(barrierBtn);
      const barrierNote = document.createElement('div');
      barrierNote.className = 'milestone-hero-offer-note';
      if (!hasWallet) barrierNote.textContent = useAvax ? 'Connect a wallet on Avalanche to pay with AVAX for more barriers.' : 'Connect a wallet on DFK Chain to burn DFK Gold for more barriers.';
      else if (milestoneTxnPending) barrierNote.textContent = `${game.milestoneOfferTxnLabel || 'Purchase'} submitting…`;
      else if (game.dfkGoldSwapPending) barrierNote.textContent = 'Waiting for wallet confirmation…';
      else if (!useAvax && walletDfkgold < barrierOffer.burnCost) barrierNote.textContent = `Need ${barrierOffer.burnCost.toLocaleString()} DFK Gold in the connected wallet.`;
      else barrierNote.textContent = `Buying now raises your barrier cap by ${barrierOffer.barrierCount} for the rest of this run.`;
      actions.appendChild(barrierNote);
    }
    const skipBtn = document.createElement('button');
    skipBtn.type = 'button';
    skipBtn.className = 'secondary small-action milestone-hero-offer-btn';
    skipBtn.textContent = milestoneTxnPending ? 'Submitting…' : 'Skip offer';
    skipBtn.disabled = milestoneTxnPending;
    skipBtn.addEventListener('click', () => finishMilestoneOffer());
    actions.appendChild(skipBtn);
    modal.classList.remove('hidden');
  }

  async function beginMilestoneBarrierOffer() {
    const offer = game.milestoneBarrierOffer;
    if (!offer) return;
    setMilestoneOfferTxnPending('Barrier purchase');
    try {
      await performVerifiedDfkgoldBurnPurchase(offer.burnCost, 0, {
        pendingBannerText: `Burning ${offer.burnCost.toLocaleString()} DFK Gold for ${offer.barrierCount} more barriers…`,
      });
      game.bonusBarrierCount = 0;
      game.phase = SETUP_PHASES.OBSTACLES;
      els.startWaveBtn.disabled = true;
      finishMilestoneOffer(false);
      setInstruction(`Place ${getTargetPlayerObstacleCount()} player obstacles.`);
      log(`Barrier bundle unlocked at wave ${offer.wave}: +${offer.barrierCount} barriers through the legacy disabled path.`);
      showBanner(`Barrier cap remains ${BASE_PLAYER_BARRIER_COUNT}.`, 2400);
      render();
    } catch (_error) {  } finally {
      clearMilestoneOfferTxnPending();
    }
  }

