  function getGlobalEnemyHpRange(waveNumberOverride = null) {
    const hpValues = [];
    const activeMutation = game.activeMutation && game.activeMutation.apply ? game.activeMutation : null;
    const waveNumber = Number(waveNumberOverride ?? game.waveNumber ?? 0);
    const earlyWaveMultiplier = getEarlyWaveStatMultiplier(waveNumber);
    const postWave15StatMultiplier = getPostWave15StatMultiplier(waveNumber);

    for (const template of Object.values(ENEMY_TEMPLATES)) {
      const hp = template.hp * (1 + Math.max(0, waveNumber - 1) * 0.12) * earlyWaveMultiplier * postWave15StatMultiplier;
      const probe = { hp, maxHp: hp, isBoss: false, moveInterval: template.moveInterval, attackInterval: template.attackInterval, damage: template.damage };
      if (activeMutation) activeMutation.apply(probe);
      hpValues.push(probe.maxHp || probe.hp || hp);
    }

    for (const boss of BOSSES) {
      const hp = boss.hp * earlyWaveMultiplier;
      const probe = { hp, maxHp: hp, isBoss: true, moveInterval: boss.moveInterval, attackInterval: boss.attackInterval, damage: boss.damage };
      if (activeMutation) activeMutation.apply(probe);
      hpValues.push(probe.maxHp || probe.hp || hp);
    }

    const minHp = Math.min(...hpValues);
    const maxHp = Math.max(...hpValues);
    return { minHp, maxHp };
  }


  function getBossVisualPhaseIndex(waveNumber) {
    const wave = Math.max(1, Number(waveNumber || 1));
    return Math.floor((wave - 1) / 10) % 4;
  }

  function getBossVisualFilter(enemy) {
    const phase = getBossVisualPhaseIndex(game.waveNumber);
    const filters = [
      'brightness(1) saturate(1) contrast(1)',
      'brightness(0.95) saturate(7.5) sepia(0.95) hue-rotate(-18deg) contrast(1.02)',
      'brightness(1.02) saturate(7.2) sepia(0.98) hue-rotate(12deg) contrast(1.04)',
      'brightness(0.96) saturate(6.1) sepia(0.95) hue-rotate(238deg) contrast(1.03)'
    ];
    return filters[phase] || filters[0];
  }

  function getPackbocSpritePath(enemy) {
    if (enemy && enemy.type === 'skitter') return 'assets/blub.gif';
    return 'assets/summoner-assistant.gif';
  }

  function createEnemySlowSnowflake(px, py, visualWidth, visualHeight, isBoss) {
    const badge = document.createElement('div');
    const size = Math.max(11, Math.round((isBoss ? 0.16 : 0.18) * Math.min(visualWidth, visualHeight)));
    badge.className = `enemy-slow-snowflake${isBoss ? ' boss-slow-snowflake' : ''}`;
    badge.textContent = '❄';
    badge.style.left = `${Math.round(px - (visualWidth / 2) + Math.max(2, visualWidth * 0.08))}px`;
    badge.style.top = `${Math.round(py - (visualHeight / 2) + Math.max(1, visualHeight * 0.04))}px`;
    badge.style.fontSize = `${size}px`;
    return badge;
  }

  function createEnemyLightOrbBadge(px, py, visualWidth, visualHeight, isBoss, index = 0) {
    const badge = document.createElement('div');
    const size = Math.max(8, Math.round((isBoss ? 0.15 : 0.16) * Math.min(visualWidth, visualHeight)));
    badge.style.position = 'absolute';
    badge.style.left = `${Math.round(px - (visualWidth / 2) + Math.max(2, visualWidth * 0.08) + (index * (size + 3)))}px`;
    badge.style.top = `${Math.round(py - (visualHeight / 2) + Math.max(1, visualHeight * 0.04))}px`;
    badge.style.width = `${size}px`;
    badge.style.height = `${size}px`;
    badge.style.borderRadius = '50%';
    badge.style.pointerEvents = 'none';
    badge.style.background = 'radial-gradient(circle, rgba(255,255,240,0.98) 0%, rgba(255,241,166,0.92) 45%, rgba(255,210,70,0.55) 75%, rgba(255,210,70,0.08) 100%)';
    badge.style.boxShadow = '0 0 8px rgba(255,236,130,0.95), 0 0 16px rgba(255,236,130,0.45)';
    return badge;
  }

  function applyVersionStamp() {
    document.documentElement.setAttribute('data-app-version', APP_VERSION);
    document.title = `DFK Defender ${APP_VERSION}`;
    const versionEl = document.getElementById('versionBadge');
    if (versionEl) versionEl.textContent = APP_VERSION;
  }

  function computeEnemyVisualSizeFromSpawnHp(spawnHp, waveNumberOverride = null) {
    const sampleTile = game.grid && game.grid[0] && game.grid[0].el ? game.grid[0].el : null;
    const tileWidth = sampleTile ? sampleTile.offsetWidth : 36;
    const maxSize = tileWidth * 0.75;
    const minSize = Math.max(10, tileWidth * 0.28);
    const { minHp, maxHp } = getGlobalEnemyHpRange(waveNumberOverride);
    const range = Math.max(1, maxHp - minHp);
    const normalized = Math.max(0, Math.min(1, (spawnHp - minHp) / range));
    return Math.max(minSize, Math.min(maxSize, minSize + (maxSize - minSize) * Math.sqrt(normalized)));
  }

  function getEnemyVisualSize(enemy) {
    if (enemy.visualSizePx) return enemy.visualSizePx;
    const spawnHp = enemy.spawnMaxHp || enemy.maxHp || enemy.hp || 1;
    return computeEnemyVisualSizeFromSpawnHp(spawnHp);
  }

  function cleanupEntities() {
    for (const enemy of [...game.enemies]) {
      if (enemy.hp <= 0) {
        awardKill(enemy);
        if (enemy.isFlyingSiege) game.eliteFinalSpawnKilledWave = game.waveNumber;
        game.enemies = game.enemies.filter(e => e.id !== enemy.id);
        markProgress(`${enemy.name} died.`);
      }
    }
    for (const tower of [...game.towers]) {
      if (tower.hp <= 0) {
        if (tower.type === 'warrior' && !tower.isSatellite && !tower.isChampion) rememberWarriorNftForReplacement(tower);
        triggerExplodingStatue(tower);
        removeTower(tower, `${tower.name} fell.`);
      }
    }
  }

  function awardKill(enemy) {
    let jewel = enemy.jewel;
    if (enemy.killedBy === 'pirate') jewel *= (1 + game.modifiers.pirateSteal);
    const liveWaveGoldBonusMultiplier = getLiveWaveGoldBonusMultiplier();
    if (liveWaveGoldBonusMultiplier > 1) jewel *= liveWaveGoldBonusMultiplier;
    game.jewel += jewel;
    updateQuestMetric('killsTotal', 1);
    updateWeeklyBountyMetric('killsTotal', 1);
    if (enemy.isBoss) {
      updateQuestMetric('killsBoss', 1);
      updateWeeklyBountyMetric('killsBoss', 1);
    }
    else if (enemy.type === 'skitter') updateQuestMetric('killsSkitter', 1);
    else {
      const enemySizeKey = getEnemyOccupancyClass(enemy);
      if (enemySizeKey === 'large') updateQuestMetric('killsLarge', 1);
      else if (enemySizeKey === 'medium') updateQuestMetric('killsMedium', 1);
      else updateQuestMetric('killsSmall', 1);
    }
    if (enemy.sourceElite || enemy.isBoss || enemy.isFlyingSiege || enemy.isBossWaveSkitter) updateWeeklyBountyMetric('killsElite', 1);
    if (enemy.killedBy && enemy.killedBy !== 'statue') updateWeeklyBountyMetric('heroKills', 1);
    if (game.modifiers.berserkerFrenzyLoop && enemy.killedBy === 'berserker') {
      const berserker = (game.towers || []).find((tower) => tower && tower.id === enemy.lastHitTowerId && tower.type === 'berserker');
      if (berserker) {
        berserker.berserkerFrenzyKillsThisWave = Math.max(0, Number(berserker.berserkerFrenzyKillsThisWave || 0)) + 1;
        berserker.berserkerFrenzyDamageMult = Math.min(2.5, 1 + (berserker.berserkerFrenzyKillsThisWave * 0.05));
      }
    }
    if (String(enemy.lastHitMethod || 'basic_attack') !== 'basic_attack') updateWeeklyBountyMetric('abilityKills', 1);
    if (enemy.debuffs && getEnemySlowPercent(enemy) > 0) updateWeeklyBountyMetric('killsSlowed', 1);
    if (enemy.debuffs && enemy.debuffs.burning) updateWeeklyBountyMetric('killsBurning', 1);
    if (enemy.debuffs && enemy.debuffs.stunned) updateWeeklyBountyMetric('killsStunned', 1);
    if (enemy.spawnedAt && (now() - Number(enemy.spawnedAt || 0)) <= 1000) updateWeeklyBountyMetric('killsQuickSpawn', 1);
    if (portalDistance(enemy) <= 2) updateWeeklyBountyMetric('killsNearPortal', 1);
    if ((game.towers || []).some((tower) => isStatueTower(tower) && tower.hp > 0 && dist(tower, enemy) <= 1)) updateWeeklyBountyMetric('killsNearStatue', 1);
    if (getLiveWaveCount() >= 2) updateWeeklyBountyMetric('killsMultiWave', 1);
    if (getLiveWaveCount() >= 3) updateWeeklyBountyMetric('killsMulti3', 1);
    const portalPct = Number(game.portalHp || 0) / 2500;
    if (portalPct < 0.75) updateWeeklyBountyMetric('killsPortalBelow75', 1);
    if (portalPct < 0.25) updateWeeklyBountyMetric('killsPortalBelow25', 1);
    if (String(enemy.killedBy || '').startsWith('champion_')) updateWeeklyBountyMetric('championKills', 1);
    updateQuestMetric('goldEarned', jewel);
    const liveWaveGoldBonusLabel = getLiveWaveGoldBonusLabel();
    log(`${enemy.name} died. +${formatJewel(jewel)} Gold${liveWaveGoldBonusLabel ? ` (${liveWaveGoldBonusLabel} live bonus)` : ''}.`);
  }

  function damageEnemy(sourceTower, enemy, amount, message, damageMethod = null) {
    let damage = amount;
    if (sourceTower && sourceTower.type === 'pirate' && game.modifiers.jackSparrow && !damageMethod?.ignoreMiss && Math.random() < 0.10) {
      createHitFlash(enemy.x, enemy.y, 'pirate', 'MISS');
      if (message && chance(0.2)) log(`${sourceTower.name} missed ${enemy.name}.`);
      return 0;
    }
    if (enemy.debuffs?.warning_shot) damage *= (1 + Number(enemy.debuffs.warning_shot.bonusDamageTaken || 0.3));
    if (enemy.debuffs?.chrono_purge) damage *= (1 + Number(enemy.debuffs.chrono_purge.bonusDamageTaken || CHRONO_PURGE_BONUS_DAMAGE_TAKEN));
    if (enemy.debuffs?.berserkerFear) damage *= (1 + Number(enemy.debuffs.berserkerFear.bonusDamageTaken || 0.25));
    if (enemy.reductionUntil && now() < enemy.reductionUntil) damage *= 0.5;
    const appliedDamage = Math.max(0, Math.min(Number(enemy.hp || 0), Number(damage || 0)));
    enemy.hp -= damage;
    if (sourceTower) {
      enemy.killedBy = sourceTower.type;
      enemy.lastHitTowerId = sourceTower.id;
      enemy.lastHitMethod = String(damageMethod?.key || 'basic_attack');
      const methodKey = String(damageMethod?.key || 'basic_attack');
      const methodLabel = String(damageMethod?.label || 'Basic Attack');
      recordTowerDamage(sourceTower, appliedDamage, methodKey, methodLabel);
      updateQuestMetric('damageTotal', appliedDamage);
      if (!sourceTower.isSatellite && !isStatueTower(sourceTower)) updateWeeklyBountyMetric('heroDamage', appliedDamage);
      applyMonkDarkSiphon(sourceTower, appliedDamage);
      const baseDamage = Math.max(1, Number(sourceTower.damage || 0) || 0);
    }
    if (sourceTower) {
      if (sourceTower.type === 'berserker' && Math.random() < 0.25) applyDebuff(enemy, 'blind', 6, { missChance: 0.25, sourceTowerId: sourceTower.id });
      const towerCanPullAggro = sourceTower.type === 'warrior' || isStatueTower(sourceTower);
      const aggroGain = damage * (towerCanPullAggro ? 0.18 : 0.04);
      enemy.threat[sourceTower.id] = (enemy.threat[sourceTower.id] || 0) + aggroGain;
      enemy.lastAggroAt = now();
      const currentThreat = enemy.aggroTargetId ? (enemy.threat[enemy.aggroTargetId] || 0) : 0;
      const portalBiasDistance = portalDistance(enemy);
      const towerDistance = Math.abs(enemy.x - sourceTower.x) + Math.abs(enemy.y - sourceTower.y);
      if (towerCanPullAggro && canEnemyAggroTower(enemy, sourceTower) && (!enemy.aggroTargetId || enemy.threat[sourceTower.id] > currentThreat * 2.4) && towerDistance <= portalBiasDistance) {
        enemy.aggroTargetId = sourceTower.id;
      }
      if (!damageMethod?.suppressAttackLine) {
        const isBasicAttackVisual = !damageMethod?.key || damageMethod?.key === 'basic_attack';
        if (!isBasicAttackVisual || Math.random() < 0.5) {
          createAttackLine(sourceTower, enemy, heroColorKey(sourceTower.type));
        }
      }
      createHitFlash(enemy.x, enemy.y, heroColorKey(sourceTower.type), `-${Math.round(damage)}`);
      markProgress(`${sourceTower.name} damaged ${enemy.name}.`);
    } else {
      createHitFlash(enemy.x, enemy.y, 'default', `-${Math.round(damage)}`);
    }
    if (message && chance(0.15)) log(`${message} for ${Math.round(damage)}.`);
  }

  function damageTower(gameState, tower, amount, message, attacker = null) {
    let damage = amount;
    if (attacker) {
      const dragoon = (gameState.towers || []).find((entry) => entry && entry.type === 'champion_dragoon' && entry.hp > 0 && entry.x === attacker.x && entry.y === attacker.y);
      if (dragoon) damage *= 0.75;
    }
    const warriorOrStatue = tower && (tower.type === 'warrior' || isStatueTower(tower));
    if (warriorOrStatue && hasUnlockedSeerEvasion() && Math.random() < SEER_EVASION_CHANCE) {
      createHitFlash(tower.x, tower.y, 'seer', 'MISS', { centerText: true, sizeMult: 1.25, duration: 500 });
      const seerSource = (gameState.towers || []).find((entry) => entry && entry.type === 'seer' && entry.hp > 0);
      if (seerSource) seerSource.damageAvoided = Math.max(0, Number(seerSource.damageAvoided || 0)) + Math.max(0, Number(damage || 0));
      if (message && chance(0.2)) log(`${tower.name} evaded the attack.`);
      return 0;
    }
    if (attacker?.debuffs?.blind && Math.random() < Number(attacker.debuffs.blind.missChance || 0.25)) {
      createHitFlash(tower.x, tower.y, 'warrior', 'MISS', { centerText: true, sizeMult: 1.15, duration: 500 });
      if (message && chance(0.2)) log(`${attacker.name} missed ${tower.name}.`);
      return 0;
    }
    if (tower.type === 'warrior' && game.modifiers.shieldWall && game.towers.some(t => t.type === 'priest' && dist(t, tower) === 1)) {
      damage *= 0.93;
    }
    tower.hp -= damage;
    if (tower.hp <= 0) {
      const sage = (gameState.towers || []).find((entry) => entry && entry.type === 'champion_sage' && entry.hp > 0 && entry.championReviveAvailable !== false && entry.id !== tower.id);
      if (sage) {
        sage.championReviveAvailable = false;
        tower.hp = tower.maxHp;
        applyBuff(tower, 'championSageShield', 3, {});
        showBanner('Sage passive: Live Forever', 1800);
      }
    }
    markProgress(`${tower.name} took damage.`);
    if (message && chance(0.2)) log(`${message} for ${Math.round(damage)}.`);
    return damage;
  }

  function healTower(tower, amount, message, options = null) {
    const allowStatue = !!(options && options.allowStatue);
    if (isStatueTower(tower) && !allowStatue) return;
    const sourceTowerId = options && options.sourceTowerId ? options.sourceTowerId : null;
    const sourceTower = sourceTowerId ? getTowerById(sourceTowerId) : null;
    let finalAmount = Math.max(0, Number(amount || 0));
    if (sourceTower && isGen0BonusTower(sourceTower)) {
      finalAmount *= Math.max(GEN0_WALLET_HERO_HEALING_MULTIPLIER, Number(sourceTower.healingPowerMultiplier || 1));
    }
    const beforeHp = Number(tower.hp || 0);
    tower.hp = Math.min(tower.maxHp, tower.hp + finalAmount);
    const healed = Math.max(0, Number(tower.hp || 0) - beforeHp);
    if (sourceTowerId) {
      if (sourceTower) {
        const healMethodKey = String(options?.methodKey || options?.healingMethodKey || 'healing');
        const healMethodLabel = String(options?.methodLabel || options?.healingMethodLabel || 'Healing');
        recordTowerHealing(sourceTower, healed, healMethodKey, healMethodLabel);
        if (['priest', 'seer', 'champion_sage'].includes(String(sourceTower.type || ''))) updateWeeklyBountyMetric('supportHealing', healed);
      }
    }
    markProgress(`${tower.name} was healed.`);
    if (message && chance(0.2)) log(`${message} for ${Math.round(healed)}.`);
    return healed;
  }

  function applyBuff(unit, keyName, seconds, data) {
    unit.buffs[keyName] = { ...data, until: now() + seconds * 1000 };
  }

  function applyDebuff(unit, keyName, seconds, data) {
    if (!unit.debuffs) unit.debuffs = {};
    const until = now() + seconds * 1000;
    if (keyName === 'kraken' && unit.debuffs.kraken) {
      const existing = unit.debuffs.kraken;
      unit.debuffs.kraken = {
        ...existing,
        ...data,
        // Kraken should refresh/maintain one active effect, never stack a second Kraken slow or damage tick.
        percent: Math.max(Number(existing.percent || 0), Number(data?.percent || 0)),
        damage: Math.max(Number(existing.damage || 0), Number(data?.damage || 0)),
        nextTickAt: existing.nextTickAt || data?.nextTickAt || now() + 1000,
        until: Math.max(Number(existing.until || 0), until)
      };
      return;
    }
    unit.debuffs[keyName] = { ...data, until };
  }

  function applyDebuffTickDamage(unit, debuff, amount, methodKey, methodLabel) {
    let damage = Math.max(0, Number(amount || 0));
    if (unit?.debuffs?.chrono_purge) damage *= (1 + Number(unit.debuffs.chrono_purge.bonusDamageTaken || CHRONO_PURGE_BONUS_DAMAGE_TAKEN));
    if (!damage || !unit || unit.hp <= 0) return;
    const appliedDamage = Math.max(0, Math.min(Number(unit.hp || 0), damage));
    unit.hp -= damage;
    const sourceTower = debuff?.sourceTowerId ? getTowerById(debuff.sourceTowerId) : null;
    if (sourceTower) {
      unit.killedBy = sourceTower.type;
      recordTowerDamage(sourceTower, appliedDamage, methodKey, methodLabel);
      updateQuestMetric('damageTotal', appliedDamage);
      const towerCanPullAggro = sourceTower.type === 'warrior' || isStatueTower(sourceTower);
      const aggroGain = damage * (towerCanPullAggro ? 0.18 : 0.04);
      unit.threat[sourceTower.id] = (unit.threat[sourceTower.id] || 0) + aggroGain;
      createHitFlash(unit.x, unit.y, heroColorKey(sourceTower.type), Math.round(appliedDamage).toString());
    }
  }

  function tickGroundBurnEffects(current) {
    game.groundBurnEffects = (game.groundBurnEffects || []).filter(effect => effect.until > current);
    for (const effect of game.groundBurnEffects) {
      if (!effect.nextTickAt || current < effect.nextTickAt) continue;
      const tileSet = new Set((effect.tiles || []).map(tile => `${tile.x},${tile.y}`));
      for (const enemy of game.enemies) {
        if (enemy.hp <= 0) continue;
        if (!tileSet.has(`${enemy.x},${enemy.y}`)) continue;
        applyDebuffTickDamage(enemy, { sourceTowerId: effect.sourceTowerId }, effect.tickDamage, 'torn_soul_burn', 'Torn Soul Burn');
      }
      effect.nextTickAt = current + 1000;
    }
  }

  function tickEffects(unit, current) {
    if (unit.buffs) {
      for (const [name, buff] of Object.entries(unit.buffs)) {
        if (buff.until && current >= buff.until) { delete unit.buffs[name]; continue; }
        if (buff.hotHeal && buff.nextTickAt && current >= buff.nextTickAt && unit.hp > 0) {
          healTower(unit, buff.hotHeal, null);
          buff.nextTickAt = current + 1000;
        }
      }
    }
    if (unit.debuffs) {
      for (const [name, debuff] of Object.entries(unit.debuffs)) {
        if (debuff.until && current >= debuff.until) {
          delete unit.debuffs[name];
          continue;
        }
        if (name === 'eagle_nest' && unit.hp > 0 && debuff.nextTickAt && current >= debuff.nextTickAt) {
          applyDebuffTickDamage(unit, debuff, debuff.damage, 'eagle_nest', "Assassin's Training");
          debuff.nextTickAt = current + 1000;
        }
        if (name === 'kraken' && unit.hp > 0 && debuff.nextTickAt && current >= debuff.nextTickAt) {
          applyDebuffTickDamage(unit, debuff, debuff.damage, 'kraken', 'Kraken');
          debuff.nextTickAt = current + 1000;
        }
        if (name === 'bleed' && unit.hp > 0 && debuff.nextTickAt && current >= debuff.nextTickAt) {
          applyDebuffTickDamage(unit, debuff, (debuff.damagePercent || 0.03) * unit.maxHp, 'bleed', 'Bleed');
          debuff.nextTickAt = current + 1000;
        }
        if (name === 'burning' && unit.hp > 0 && debuff.nextTickAt && current >= debuff.nextTickAt) {
          applyDebuffTickDamage(unit, debuff, (debuff.damagePercent || (FIREBOLT_BURN_TOTAL_HEALTH_PERCENT / FIREBOLT_BURN_DURATION_SECONDS)) * unit.maxHp, 'burning', 'Burning');
          debuff.nextTickAt = current + 1000;
        }
      }
    }
  }


  function getActiveSlowTotems() {
    const currentWave = Number(game.waveNumber || 0);
    game.slowTotems = (game.slowTotems || []).filter(t => Number(t.expiresAfterWave || 0) > currentWave);
    return game.slowTotems;
  }

  function addSlowTotem(caster, placement = null) {
    const totem = {
      id: `slow-totem-${caster.id}-${Date.now()}`,
      x: Number.isFinite(placement?.x) ? placement.x : caster.x,
      y: Number.isFinite(placement?.y) ? placement.y : caster.y,
      sourceId: caster.id,
      createdAtWave: Number(game.waveNumber || 0),
      expiresAfterWave: Number(game.waveNumber || 0) + BLINDING_LIGHT_TOTEM_DURATION_WAVES,
      range: BLINDING_LIGHT_TOTEM_RANGE,
      percent: BLINDING_LIGHT_TOTEM_SLOW_PERCENT,
      attackSlowPercent: BLINDING_LIGHT_TOTEM_ATTACK_SLOW_PERCENT,
    };
    if (!game.slowTotems) game.slowTotems = [];
    game.pendingManualAbilityPlacement = null;
    game.slowTotems.push(totem);
    return totem;
  }

  function getSlowTotemSlowPercent(enemy) {
    let best = 0;
    const linger = enemy?.debuffs?.blinding_light_linger;
    if (linger && (!linger.until || now() < linger.until)) best = Math.max(best, Number(linger.percent || 0));
    for (const totem of getActiveSlowTotems()) {
      if (Math.abs(enemy.x - totem.x) + Math.abs(enemy.y - totem.y) <= totem.range) {
        best = Math.max(best, Number(totem.percent || 0.35));
      }
    }
    return best;
  }

  function getBlindingLightAttackSlowPercent(enemy) {
    let best = 0;
    const linger = enemy?.debuffs?.blinding_light_linger;
    if (linger && (!linger.until || now() < linger.until)) best = Math.max(best, Number(linger.attackSlowPercent || 0));
    for (const totem of getActiveSlowTotems()) {
      if (Math.abs(enemy.x - totem.x) + Math.abs(enemy.y - totem.y) <= totem.range) {
        best = Math.max(best, Number(totem.attackSlowPercent || 0));
      }
    }
    return best;
  }

  function beginManualAbilityPlacement(tower, abilityKey) {
    if (!tower || !abilityKey) return false;
    game.pendingManualAbilityPlacement = { towerId: tower.id, abilityKey };
    const abilityName = tower.template?.abilities?.find(a => a.key === abilityKey)?.name || 'Ability';
    showBanner(`Pick an open tile for ${abilityName}`, 1600);
    render();
    return true;
  }

  function placeManualAbilityAt(x, y) {
    const pending = game.pendingManualAbilityPlacement;
    if (!pending) return false;
    const tower = getTowerById(pending.towerId);
    if (!tower) { game.pendingManualAbilityPlacement = null; render(); return false; }
    if (!isOpenForTower(x, y)) { showBanner('Pick an open tile for the totem', 1200); return true; }
    if (pending.abilityKey === 'slow_totem') {
      if (!castAbility(tower, 'slow_totem', { placement: { x, y } })) return true;
      game.pendingManualAbilityPlacement = null;
      render();
      return true;
    }
    return false;
  }

  function castAbility(tower, abilityKey, opts = {}) {
    if (tower && abilityKey) recordReplayEvent('ability_cast_attempt', { towerId: tower.id, type: tower.type, abilityKey, x: tower.x, y: tower.y });
    if (!isAbilityUnlocked(tower, abilityKey)) return;
    const readyAt = getTowerAbilityReadyAt(tower, abilityKey);
    if (now() < readyAt) return;
    const powerMult = getAbilityPowerMultiplier(tower, abilityKey);
    const ctx = { game, tower };
    const handlers = {
      gladiator_strike() {
        return false;
      },
      whirlwind() {
        const targets = game.enemies.filter(e => dist(e, tower) <= 2);
        const tiles = [];
        for (let xx = tower.x - 2; xx <= tower.x + 2; xx++) {
          for (let yy = tower.y - 2; yy <= tower.y + 2; yy++) {
            if (inBounds(xx, yy) && Math.abs(xx - tower.x) + Math.abs(yy - tower.y) <= 2) tiles.push({ x: xx, y: yy });
          }
        }
        createTileFlashArea(tiles, 'warrior');
        if (!targets.length) return false;
        targets.forEach(e => damageEnemy(tower, e, 60 * powerMult, null, { key: 'whirlwind', label: 'Whirlwind' }));
        return true;
      },
      rapid_onslaught() {
        applyBuff(tower, 'rapid_onslaught', 4, { strength: 1 * powerMult });
        return true;
      },
      shield_bash() {
        const target = nearestEnemyForWarrior(tower);
        if (!target || chebyshevDist(tower, target) > 1) return false;
        damageEnemy(tower, target, tower.damage * 1.5, `${tower.name} used Shield Bash`, { key: 'shield_bash', label: 'Shield Bash' });
        const sameTileTargets = game.enemies.filter(e => e.x === target.x && e.y === target.y);
        sameTileTargets.forEach(enemy => pushEnemyAwayFromTile(enemy, tower.x, tower.y, 5));
        return true;
      },
      taunt() {
        const targets = game.enemies.filter(e => dist(e, tower) <= 2 * powerMult);
        if (!targets.length) return false;
        targets.forEach(e => { if (dist(e, tower) <= 2 * powerMult) { e.tauntedTo = tower; e.tauntUntil = now() + 3000 * powerMult; } });
        return true;
      },
      multi_shot() {
        const targets = game.enemies.filter(e => dist(e, tower) <= tower.range).sort((a, b) => dist(tower, a) - dist(tower, b)).slice(0, 5);
        if (!targets.length) return false;
        const multiShotLevelBonusPerArrow = getAbilityLevelBonus(tower, 1) / 3;
        targets.forEach(e => { createAttackLine(tower, e, 'archer', 'archer-multishot'); damageEnemy(tower, e, (tower.damage * 0.7) + (MULTI_SHOT_BASE_DAMAGE_BONUS * 0.7) + 1 + multiShotLevelBonusPerArrow, null, { key: 'multi_shot', label: 'Multi-Shot' }); });
        createTileFlashArea(targets.map(e => ({x:e.x,y:e.y})), 'archer');
        return true;
      },
      rapid_shot() {
        applyBuff(tower, 'rapid_shot', 4, { bonus: 0.8 * powerMult });
        return true;
      },
      piercing_shot() {
        const targets = game.enemies.filter(e => dist(e, tower) <= tower.range).sort((a, b) => dist(tower, a) - dist(tower, b)).slice(0, 3);
        if (!targets.length) return false;
        const abilityDamage = tower.damage + 2 + getAbilityLevelBonus(tower);
        [1, 0.8, 0.6, 0.45, 0.35].forEach((mult, i) => { if (targets[i]) damageEnemy(tower, targets[i], abilityDamage * mult * powerMult, null, { key: 'piercing_shot', label: 'Piercing Shot' }); });
        return true;
      },
      eagle_nest() {
        return false;
      },
      firebolt() {
        const target = (tower.type === 'warrior' || tower.type === 'champion_dreadknight') ? nearestEnemyForWarrior(tower) : nearestEnemyInRange(tower, tower.range);
        if (!target) return false;
        const fireboltDamage = (42 + getAbilityLevelBonus(tower, 1)) * game.modifiers.wizardSpellDamage;
        const sameTileTargets = game.enemies.filter(e => e.x === target.x && e.y === target.y).slice(0, 2);
        sameTileTargets.forEach(e => {
          damageEnemy(tower, e, fireboltDamage, `${tower.name} cast Firebolt`, { key: 'firebolt', label: 'Firebolt' });
          if (!e.debuffs.burning) {
            applyDebuff(e, 'burning', FIREBOLT_BURN_DURATION_SECONDS, {
              damagePercent: FIREBOLT_BURN_TOTAL_HEALTH_PERCENT / FIREBOLT_BURN_DURATION_SECONDS,
              nextTickAt: now() + 1000,
              sourceTowerId: tower.id
            });
          }
        });
        return true;
      },
      frost_bolt() {
        return false;
      },
      fireball() {
        const target = (tower.type === 'warrior' || tower.type === 'champion_dreadknight') ? nearestEnemyForWarrior(tower) : nearestEnemyInRange(tower, tower.range);
        if (!target) return false;
        const targets = game.enemies.filter(e => dist(e, target) <= 2);
        const impactedTiles = [];
        const seenImpactedTiles = new Set();
        targets.forEach((enemy) => {
          const impactedKey = `${enemy.x},${enemy.y}`;
          if (seenImpactedTiles.has(impactedKey)) return;
          seenImpactedTiles.add(impactedKey);
          impactedTiles.push({ x: enemy.x, y: enemy.y });
        });
        if (!impactedTiles.length) impactedTiles.push({ x: target.x, y: target.y });
        impactedTiles.sort((a, b) => (a.y - b.y) || (a.x - b.x));
        const rowOrder = [...new Set(impactedTiles.map(tile => tile.y))];
        const baseCastAt = now();
        const rowRippleDelayMs = 95;
        const withinRowDelayMs = 30;
        impactedTiles.forEach((tile, tileIndex) => {
          const rowIndex = Math.max(0, rowOrder.indexOf(tile.y));
          const rowStartAt = baseCastAt + (rowIndex * rowRippleDelayMs);
          const withinRowIndex = impactedTiles
            .slice(0, tileIndex)
            .filter(previousTile => previousTile.y === tile.y)
            .length;
          const projectileMeta = createFireballProjectileEffect(tower, tile, {
            startedAt: rowStartAt + (withinRowIndex * withinRowDelayMs),
            durationMs: 560,
          });
          if (projectileMeta) {
            createExplosionEffect(tile.x, tile.y, 'wizard', 0.65, 420, FIREBALL_GIF_PATH, 'fireball-orange-burst', [{ x: tile.x, y: tile.y }], { startedAt: projectileMeta.arrivalAt - 70 });
          }
        });
        const fireballDamage = (70 + getAbilityLevelBonus(tower, 1)) * powerMult * game.modifiers.wizardSpellDamage;
        targets.forEach(e => { createAttackLine(tower, e, 'wizard', 'wizard-fireball'); damageEnemy(tower, e, fireballDamage, null, { key: 'fireball', label: 'Fireball' }); });
        const areaTiles = [];
        for (let xx = target.x - 2; xx <= target.x + 2; xx++) for (let yy = target.y - 2; yy <= target.y + 2; yy++) if (inBounds(xx, yy) && Math.abs(xx - target.x) + Math.abs(yy - target.y) <= 2) areaTiles.push({x:xx,y:yy});
        createTileFlashArea(areaTiles, 'wizard');
        return true;
      },
      frost_lance() {
        const target = (tower.type === 'warrior' || tower.type === 'champion_dreadknight') ? nearestEnemyForWarrior(tower) : nearestEnemyInRange(tower, tower.range);
        if (!target) return false;
        let dmg = 99 * powerMult * game.modifiers.wizardSpellDamage;
        if (getEnemySlowPercent(target) > 0) dmg *= 2;
        damageEnemy(tower, target, dmg, `${tower.name} cast Frost Lance`, { key: 'frost_lance', label: 'Frost Lance' });
        return true;
      },
      temporal_restoration() {
        return false;
      },
      warstone() {
        const target = nearestEnemyInRange(tower, tower.range);
        if (!target) return false;
        const targetTiles = collectTileTargets(target, 3, 1);
        const from = getTowerPixelCenter(tower);
        let hitAny = false;
        for (const tileTarget of targetTiles) {
          const tilePos = getTilePixelPosition(tileTarget.x, tileTarget.y);
          createProjectileEffect({
            kind: 'seer-warstone',
            fromX: from.x,
            fromY: from.y,
            toX: tilePos.left + (tilePos.width / 2),
            toY: tilePos.top + (tilePos.height / 2),
            durationMs: 550,
            imagePath: 'assets/rock.png',
          });
          const tileEnemies = game.enemies
            .filter((enemy) => enemy.x === tileTarget.x && enemy.y === tileTarget.y)
            .slice(0, 3);
          for (const enemy of tileEnemies) {
            damageEnemy(tower, enemy, (WARSTONE_BASE_DAMAGE + getAbilityLevelBonus(tower, 1)) * getSeerDamageMultiplier(), null, { key: 'warstone', label: 'Warstone' });
            hitAny = true;
          }
        }
        createTileFlashArea(targetTiles, 'seer');
        return hitAny;
      },
      chrono_purge() {
        const target = nearestEnemyInRange(tower, tower.range);
        if (!target) return false;
        const targetTiles = collectTileTargets(target, 2, 1);
        const chronoDamage = getChronoPurgeDamage(tower);
        let hitAny = false;
        for (const tileTarget of targetTiles) {
          const tileEnemies = game.enemies
            .filter((enemy) => enemy.x === tileTarget.x && enemy.y === tileTarget.y)
            .slice(0, 3);
          for (const enemy of tileEnemies) {
            damageEnemy(tower, enemy, chronoDamage, null, { key: 'chrono_purge', label: 'Chrono Purge' });
            applyDebuff(enemy, 'chrono_purge', CHRONO_PURGE_DURATION_SECONDS, { bonusDamageTaken: CHRONO_PURGE_BONUS_DAMAGE_TAKEN });
            hitAny = true;
          }
        }
        createTileFlashArea(targetTiles, 'seer');
        return hitAny;
      },
      evasion() {
        return false;
      },
      prayer_of_healing() {
        const allies = game.towers.filter(t => dist(t, tower) <= 5 && !isStatueTower(t) && t.hp < t.maxHp);
        const statues = game.modifiers.sacredSculpting
          ? game.towers.filter(t => isStatueTower(t) && dist(t, tower) <= 5 && t.hp < t.maxHp)
          : [];
        if (!allies.length && !statues.length) return false;
        allies.forEach(a => {
          const healAmount = getPrayerOfHealingAmount(a);
          healTower(a, healAmount, null, { sourceTowerId: tower.id });
          createTowerLine(tower, a, 'priest');
        });
        statues.forEach(a => {
          const healAmount = getPrayerOfHealingAmount(a);
          healTower(a, healAmount * 0.3, null, { allowStatue: true, sourceTowerId: tower.id });
          createTowerLine(tower, a, 'priest');
        });
        return true;
      },
      slow_totem() {
        const placement = opts.placement;
        if (!placement || !Number.isFinite(placement.x) || !Number.isFinite(placement.y)) {
          beginManualAbilityPlacement(tower, 'slow_totem');
          return 'placement';
        }
        addSlowTotem(tower, placement);
        createTileFlashArea(getTilesInManhattanRange(placement.x, placement.y, BLINDING_LIGHT_TOTEM_RANGE), 'priest');
        return true;
      },
      swiftness() {
        const allies = game.towers.filter(t => dist(t, tower) <= 2);
        const hotHeal = 5 + Math.floor(tower.level / 5);
        allies.forEach(a => {
          applyBuff(a, 'swiftness', 8, { bonus: 0.25 * powerMult, hotHeal, nextTickAt: now() + 1000 });
          createTowerLine(tower, a, 'priest');
        });
        return true;
      },
      warning_shot() {
        const target = (tower.type === 'warrior' || tower.type === 'champion_dreadknight') ? nearestEnemyForWarrior(tower) : nearestEnemyInRange(tower, tower.range);
        if (!target) return false;
        const targets = game.enemies.filter(e => dist(e, target) <= 2);
        if (!targets.length) return false;
        const areaTiles = [];
        targets.forEach(enemy => {
          damageEnemy(tower, enemy, tower.damage * 0.5, `${tower.name} fired Warning Shot at ${enemy.name}`, { key: 'warning_shot', label: 'Warning Shot' });
          applyDebuff(enemy, 'warning_shot', 20, { bonusDamageTaken: 0.3 });
          areaTiles.push({ x: enemy.x, y: enemy.y });
        });
        createTileFlashArea(areaTiles, 'pirate');
        return true;
      },
      starboard_cannons() {
        const target = (tower.type === 'warrior' || tower.type === 'champion_dreadknight') ? nearestEnemyForWarrior(tower) : nearestEnemyInRange(tower, tower.range);
        if (!target) return false;
        const shots = 4 + game.modifiers.extraCannons;
        const visualShots = Math.max(1, shots - 2);
        const cannonballDamage = STARBOARD_CANNONS_BASE_DAMAGE + getAbilityLevelBonus(tower, 4);
        const spreadPatterns = [
          [{ x: 0, y: 0 }, { x: -1, y: 0 }, { x: 1, y: 0 }],
          [{ x: 0, y: 0 }, { x: 0, y: -1 }, { x: 0, y: 1 }],
          [{ x: 0, y: 0 }, { x: -1, y: -1 }, { x: 1, y: 1 }],
          [{ x: 0, y: 0 }, { x: -1, y: 1 }, { x: 1, y: -1 }],
        ];
        for (let i = 0; i < shots; i += 1) {
          const targets = game.enemies.filter(e => dist(e, target) <= 2);
          const chosen = targets.length ? pickRandom(targets) : target;
          const shotStartedAt = now() + (i * 55);
          const shouldRenderVisual = i < visualShots;
          const pattern = spreadPatterns[i % spreadPatterns.length];
          const visualTiles = [];
          const seenTiles = new Set();

          if (shouldRenderVisual) {
            for (let j = 0; j < pattern.length; j += 1) {
              const offset = pattern[j];
              const tile = { x: chosen.x + offset.x, y: chosen.y + offset.y };
              if (!inBounds(tile.x, tile.y)) continue;
              const key = `${tile.x},${tile.y}`;
              if (seenTiles.has(key)) continue;
              seenTiles.add(key);
              visualTiles.push(tile);

              const projectileMeta = createCannonballProjectileEffect(tower, tile, {
                startedAt: shotStartedAt + (j * 22),
                durationMs: 520 + (j * 10),
              });
              if (projectileMeta) {
                createExplosionEffect(tile.x, tile.y, 'pirate', 0.5, 240, CANNONBALL_IMAGE_PATH, 'pirate-cannonball-burst', [{ x: tile.x, y: tile.y }], { startedAt: projectileMeta.arrivalAt - 45 });
              }
            }
          }

          if (shouldRenderVisual && !visualTiles.length) {
            const fallbackMeta = createCannonballProjectileEffect(tower, chosen, {
              startedAt: shotStartedAt,
              durationMs: 520,
            });
            if (fallbackMeta) {
              createExplosionEffect(chosen.x, chosen.y, 'pirate', 0.5, 240, CANNONBALL_IMAGE_PATH, 'pirate-cannonball-burst', [{ x: chosen.x, y: chosen.y }], { startedAt: fallbackMeta.arrivalAt - 45 });
            }
          }

          createAttackLine(tower, chosen, 'pirate', 'pirate-cannonball');
          damageEnemy(tower, chosen, cannonballDamage, null, { key: 'starboard_cannons', label: 'Starboard Cannons' });
        }
        return true;
      },
      kraken() {
        const target = (tower.type === 'warrior' || tower.type === 'champion_dreadknight') ? nearestEnemyForWarrior(tower) : nearestEnemyInRange(tower, tower.range);
        if (!target) return false;
        const targets = game.enemies.filter(e => dist(e, target) <= 4);
        targets.forEach(e => applyDebuff(e, 'kraken', KRAKEN_DURATION_SECONDS, { damage: KRAKEN_BASE_DAMAGE * powerMult, percent: KRAKEN_SLOW_PERCENT, nextTickAt: now() + 1000, sourceTowerId: tower.id }));
        return true;
      },
      fast_fists() {
        const targets = game.enemies.filter((enemy) => chebyshevDist(enemy, tower) <= 1);
        if (!targets.length) return false;
        createMonkFastFistsEffect(tower);
        createTileFlashArea(targets.map((enemy) => ({ x: enemy.x, y: enemy.y })), 'seer');
        targets.forEach((enemy) => damageEnemy(tower, enemy, tower.damage * 2, `${tower.name} used Fast Fists`, { key: 'fast_fists', label: 'Fast Fists' }));
        return true;
      },
      windmill_kick() {
        const targets = game.enemies.filter((enemy) => dist(enemy, tower) <= 2);
        if (!targets.length) return false;
        createTileFlashArea(targets.map((enemy) => ({ x: enemy.x, y: enemy.y })), 'seer');
        targets.forEach((enemy) => damageEnemy(tower, enemy, tower.damage * 1.5, `${tower.name} used Windmill Kick`, { key: 'windmill_kick', label: 'Windmill Kick' }));
        return true;
      },
      two_handed_swing() {
        const targets = game.enemies.filter((enemy) => dist(enemy, tower) <= 2)
          .sort((a, b) => portalDistance(a) - portalDistance(b))
          .slice(0, 10);
        if (!targets.length) return false;
        createBerserkerTwoHandedSwingEffect(tower, { durationMs: 1200 });
        createTileFlashArea(targets.map((enemy) => ({ x: enemy.x, y: enemy.y })), 'warrior');
        targets.forEach((enemy) => damageEnemy(tower, enemy, tower.damage * 1.75, `${tower.name} used Two-Handed Swing`, { key: 'two_handed_swing', label: 'Two-Handed Swing' }));
        return true;
      },
      see_the_moon() {
        const targets = game.enemies.filter((enemy) => dist(enemy, tower) <= 2);
        if (!targets.length) return false;
        createTileFlashArea(targets.map((enemy) => ({ x: enemy.x, y: enemy.y })), 'warrior');
        targets.forEach((enemy) => {
          tryApplyStun(enemy, 3, 1, { sourceTowerId: tower.id });
          applyDebuff(enemy, 'berserkerFear', 3, { bonusDamageTaken: 0.25, sourceTowerId: tower.id });
        });
        showBanner('See the Moon', 900);
        return true;
      },
    };
    const ok = handlers[abilityKey]?.(ctx);
    if (ok === 'placement') return false;
    if (!ok) {
      if (!opts.silent) showBanner('No valid target in range', 1200);
      return false;
    }
    const cooldown = getAbilityCooldownSeconds(tower, abilityKey);
    let mult = 1;
    if ((tower.type === 'wizard' || tower.type === 'wizard_satellite' || tower.type === 'seer')) mult *= game.modifiers.wizardCooldown;
    if (tower.type === 'warrior') mult *= game.modifiers.warriorCooldown;
    tower.abilityReadyAt[abilityKey] = now() + cooldown * 1000 * mult;
    tower.abilityGlobalReadyAt = now() + TOWER_ABILITY_CHAIN_DELAY_MS;
    updateWeeklyBountyMetric('heroAbilityTriggers', 1);
    if (!opts.auto) {
      updateWeeklyBountyMetric('manualHeroAbilityTriggers', 1);
      log(`${tower.name} used ${abilityKey.replaceAll('_', ' ')}.`);
    }
    render();
    return true;
  }


  function clearPathPreview() {
    game.grid.forEach(tile => { tile.pathPreview = null; });
  }

  function getLiveWaveCount() {
    return Array.isArray(game.activeWavePlans) ? game.activeWavePlans.length : 0;
  }

  function getLiveWaveGoldBonusMultiplier() {
    const liveCount = getLiveWaveCount();
    if (liveCount >= 3) return 1.5;
    if (liveCount >= 2) return 1.25;
    return 1;
  }

  function getLiveWaveGoldBonusLabel() {
    const mult = getLiveWaveGoldBonusMultiplier();
    if (mult >= 1.5) return '1.5x Gold';
    if (mult >= 1.25) return '1.25x Gold';
    return '';
  }

  function syncStartWaveBonusIndicator() {
    if (!els.startWaveBonusIndicator) return;
    const liveCount = getLiveWaveCount();
    const liveWaveGoldBonusLabel = getLiveWaveGoldBonusLabel();
    if (liveCount >= 2 && liveWaveGoldBonusLabel) {
      els.startWaveBonusIndicator.textContent = `Multiwave Bonus ${liveWaveGoldBonusLabel}`;
      els.startWaveBonusIndicator.hidden = false;
    } else {
      els.startWaveBonusIndicator.textContent = '';
      els.startWaveBonusIndicator.hidden = true;
    }
  }

  function buyableWaveStart() {
    return game.phase === SETUP_PHASES.BATTLE
      && !game.relicChoices.length
      && !!game.nextWavePlan
      && !game.crashed
      && !hasActiveMilestoneOffer()
      && getLiveWaveCount() < MAX_LIVE_WAVES;
  }

  function ensureStartWaveHintEl() {
    if (els.startWaveHintEl) return els.startWaveHintEl;
    const hireSection = document.querySelector('.hire-section');
    const controlsStack = document.querySelector('.controls-stack');
    const stack = document.getElementById('startWaveStack');
    const host = hireSection || controlsStack || stack;
    if (!host) return null;
    const hint = document.createElement('div');
    hint.id = 'startWaveHint';
    hint.className = 'start-wave-hint';
    hint.hidden = true;
    hint.style.marginTop = '8px';
    hint.style.fontSize = '12px';
    hint.style.lineHeight = '1.25';
    hint.style.textAlign = 'left';
    hint.style.color = '#ffcc66';
    hint.style.textShadow = '0 0 8px rgba(0,0,0,0.42)';
    hint.style.maxWidth = '100%';
    hint.style.whiteSpace = 'normal';
    if (hireSection) {
      hireSection.insertAdjacentElement('afterend', hint);
    } else {
      host.appendChild(hint);
    }
    els.startWaveHintEl = hint;
    return hint;
  }

  function getStartWaveBlockers() {
    const blockers = [];
    const pushUnique = (message) => {
      if (!message) return;
      if (!blockers.includes(message)) blockers.push(message);
    };
    if (game.crashed) pushUnique('Resolve the runtime error');
    if (game.phase === SETUP_PHASES.PORTAL) pushUnique('Place your portal');
    if (game.phase === SETUP_PHASES.OBSTACLES) {
      pushUnique(`Place all of your barriers (${game.playerObstacleCount}/${getTargetPlayerObstacleCount()})`);
    }
    if (game.phase === SETUP_PHASES.WARRIOR) pushUnique('Place your warrior');
    if (game.startingRelicPending) pushUnique('Choose your free relic');
    else if (Array.isArray(game.relicChoices) && game.relicChoices.length) pushUnique('Choose a relic');
    if (game.continueOfferPending) pushUnique('Resolve your reward choice');
    if (hasActiveMilestoneOffer()) pushUnique('Resolve the milestone offer');
    if (getLiveWaveCount() >= MAX_LIVE_WAVES) pushUnique('Wait for a live wave slot to open');
    if (game.phase === SETUP_PHASES.BATTLE && !game.nextWavePlan && !game.crashed) pushUnique('Wait for the next wave to prepare');
    return blockers;
  }

  function syncStartWaveButtonState() {
    if (!els.startWaveBtn) return false;
    const canStart = buyableWaveStart() && !game.startingRelicPending && !game.continueOfferPending;
    els.startWaveBtn.disabled = !canStart;
    const liveCount = getLiveWaveCount();
    els.startWaveBtn.textContent = liveCount >= MAX_LIVE_WAVES ? '3 Waves Live' : (liveCount > 0 ? `Start Next Wave (${liveCount}/3 Live)` : 'Start Next Wave');
    const hintEl = ensureStartWaveHintEl();
    const blockers = canStart ? [] : getStartWaveBlockers();
    const hintText = blockers.length ? blockers.join('\n') : 'Finish setup to begin the wave';
    els.startWaveBtn.title = els.startWaveBtn.disabled ? hintText : '';
    els.startWaveBtn.setAttribute('aria-label', els.startWaveBtn.disabled ? `Start Next Wave unavailable. ${hintText.replace(/\n/g, '. ')}` : 'Start Next Wave');
    if (hintEl) {
      if (els.startWaveBtn.disabled) {
        hintEl.innerHTML = blockers.length ? blockers.map(message => `• ${message}`).join('<br>') : '• Finish setup to begin the wave';
        hintEl.hidden = false;
      } else {
        hintEl.innerHTML = '';
        hintEl.hidden = true;
      }
    }
    syncStartWaveBonusIndicator();
    return canStart;
  }

  function updateAutoStartButton() {
    if (!els.autoStartBtn) return;
    const enabled = !!game.autoStartEnabled;
    const armed = enabled && !game.runningWave && game.autoStartReadyAt > 0 && buyableWaveStart() && !game.startingRelicPending;
    let label = `Auto Start: ${enabled ? 'On' : 'Off'}`;
    if (armed) {
      const remainingMs = Math.max(0, game.autoStartDelayMs - (now() - game.autoStartReadyAt));
      label += ` (${Math.ceil(remainingMs / 1000)}s)`;
    }
    els.autoStartBtn.textContent = label;
    els.autoStartBtn.classList.toggle('active', enabled);
    els.autoStartBtn.setAttribute('aria-pressed', enabled ? 'true' : 'false');
    els.autoStartBtn.disabled = !!game.startingRelicPending;
    els.autoStartBtn.title = enabled
      ? 'Automatically starts the next ready wave after the delay.'
      : 'Enable automatic wave starts during preparation phases.';
  }

  function armAutoStartCountdown(force = false) {
    if (!game.autoStartEnabled) {
      game.autoStartReadyAt = 0;
      updateAutoStartButton();
      return false;
    }
    if (!buyableWaveStart() || game.startingRelicPending) {
      game.autoStartReadyAt = 0;
      updateAutoStartButton();
      return false;
    }
    if (force || game.autoStartReadyAt <= 0) {
      game.autoStartReadyAt = now();
      game.autoStartToken = (game.autoStartToken || 0) + 1;
    }
    updateAutoStartButton();
    return true;
  }

  function toggleAutoStart() {
    game.autoStartEnabled = !game.autoStartEnabled;
    if (!game.autoStartEnabled) {
      game.autoStartReadyAt = 0;
      game.autoStartToken = (game.autoStartToken || 0) + 1;
    } else {
      armAutoStartCountdown(true);
    }
    updateAutoStartButton();
    render();
  }

  const damageReportStyle = document.createElement('style');
  damageReportStyle.textContent = `
    .live-damage-report { width: 65%; max-width: 1120px; margin: 10px auto 0; padding: 7px 9px; border: 1px solid rgba(235, 220, 180, 0.18); border-radius: 12px; background: rgba(12, 18, 30, 0.94); box-shadow: inset 0 1px 0 rgba(255,255,255,0.03); }
    .live-damage-report.hidden { display: none; }
    .live-damage-report-header { width: 100%; display: flex; align-items: center; justify-content: space-between; gap: 10px; margin-bottom: 6px; padding: 0; border: 0; background: transparent; text-align: left; cursor: pointer; }
    .live-damage-report-header-right { display: flex; flex-direction: column; align-items: flex-end; gap: 2px; }
    .live-damage-report-kicker { font-size: 9px; letter-spacing: 0.14em; text-transform: uppercase; color: rgba(214, 197, 151, 0.74); }
    .live-damage-report-title { font-size: 13px; font-weight: 700; color: #f5edd7; }
    .live-damage-report-total { font-size: 12px; font-weight: 700; color: #9ce1ff; white-space: nowrap; }
    .live-damage-report-togglehint { font-size: 10px; color: rgba(220, 227, 239, 0.66); white-space: nowrap; }
    .live-damage-report-body { display: grid; gap: 4px; }
    .live-damage-report.is-collapsed .live-damage-report-body { display: none; }
    .live-damage-report.is-collapsed .live-damage-report-header { margin-bottom: 0; }
    .live-damage-report-row { display: grid; grid-template-columns: 24px minmax(0, 1fr) auto; gap: 8px; align-items: center; padding: 6px 8px; border-radius: 10px; background: rgba(255,255,255,0.035); }
    .live-damage-report-rank { font-size: 14px; font-weight: 700; color: rgba(245, 237, 215, 0.8); text-align: center; }
    .live-damage-report-main { min-width: 0; }
    .live-damage-report-name { font-size: 12px; font-weight: 700; color: #f5edd7; white-space: nowrap; overflow: hidden; text-overflow: ellipsis; }
    .live-damage-report-meta { font-size: 10px; color: rgba(220, 227, 239, 0.72); white-space: nowrap; overflow: hidden; text-overflow: ellipsis; }
    .live-damage-report-value { font-size: 14px; font-weight: 800; color: #78f3a4; }
    .live-damage-report-methods { display: grid; gap: 3px; margin-top: 5px; }
    .live-damage-report-method-row { display: grid; grid-template-columns: minmax(0, 1fr) auto; gap: 8px; align-items: start; padding: 3px 5px; border-radius: 7px; background: rgba(255,255,255,0.035); }
    .live-damage-report-method-label { font-size: 10px; color: rgba(245, 237, 215, 0.86); overflow: hidden; text-overflow: ellipsis; }
    .live-damage-report-method-value { font-size: 10px; font-weight: 700; color: #f5edd7; text-align: right; }
    .live-damage-report-gen0-value { display: flex; flex-wrap: wrap; justify-content: flex-end; gap: 4px 8px; color: #ffe883; text-shadow: 0 0 5px rgba(255, 210, 45, 0.26); }
    .live-damage-report-empty { padding: 6px 8px; border-radius: 10px; background: rgba(255,255,255,0.035); color: rgba(220, 227, 239, 0.78); }
    .wallet-hero-scan-status { width: 65%; max-width: 1120px; margin: 10px auto 0; padding: 8px 12px 6px; display: flex; flex-direction: column; align-items: stretch; justify-content: center; gap: 6px; border: 1px solid rgba(129, 220, 255, 0.36); border-radius: 12px; background: rgba(12, 18, 30, 0.94); color: #dff7ff; font-size: 15px; font-weight: 800; letter-spacing: 0.01em; box-shadow: inset 0 1px 0 rgba(255,255,255,0.05), 0 0 24px rgba(74, 201, 255, 0.16); pointer-events: none; animation: walletHeroScanNoticeBreathe 1.25s ease-in-out infinite alternate; }
    .wallet-hero-scan-status.hidden { display: none; }
    .wallet-hero-scan-status.is-done { border-color: rgba(120, 243, 164, 0.32); color: #dfffe8; animation: none; }
    .wallet-hero-scan-line { display: flex; align-items: center; justify-content: center; gap: 9px; text-align: center; }
    .wallet-hero-scan-spinner { width: 15px; height: 15px; border-radius: 999px; border: 2px solid rgba(223,247,255,0.22); border-top-color: #9ce1ff; animation: walletHeroScanSpin 0.62s linear infinite; flex: 0 0 auto; }
    .wallet-hero-scan-track { position: relative; height: 45px; overflow: hidden; border-radius: 999px; background: linear-gradient(90deg, rgba(156,225,255,0.10), rgba(120,243,164,0.14)); box-shadow: inset 0 0 0 1px rgba(255,255,255,0.06); }
    .wallet-hero-scan-runner { position: absolute; left: calc((100% - 92px) * var(--wallet-hero-scan-progress, 0)); bottom: -6px; width: 54px; height: 54px; object-fit: contain; image-rendering: pixelated; filter: drop-shadow(0 0 7px rgba(156,225,255,0.68)); animation: walletHeroScanBob 0.22s ease-in-out infinite alternate; }
    .wallet-hero-scan-portal { position: absolute; right: 7px; bottom: 3px; width: 31px; height: 38px; object-fit: contain; image-rendering: pixelated; filter: drop-shadow(0 0 8px rgba(137, 240, 255, 0.55)); animation: walletHeroScanPortalPulse 0.8s ease-in-out infinite alternate; }
    .wallet-hero-scan-status.is-done .wallet-hero-scan-spinner { border-color: rgba(120,243,164,0.28); border-top-color: #78f3a4; animation: walletHeroScanPulse 0.75s ease-in-out infinite alternate; }
    @keyframes walletHeroScanSpin { to { transform: rotate(360deg); } }
    @keyframes walletHeroScanPulse { from { transform: scale(0.86); opacity: 0.68; } to { transform: scale(1.08); opacity: 1; } }
    @keyframes walletHeroScanNoticeBreathe { from { transform: translateY(0); box-shadow: inset 0 1px 0 rgba(255,255,255,0.05), 0 0 16px rgba(74, 201, 255, 0.12); } to { transform: translateY(-2px); box-shadow: inset 0 1px 0 rgba(255,255,255,0.06), 0 0 28px rgba(74, 201, 255, 0.25); } }
    @keyframes walletHeroScanPortalPulse { from { transform: scale(0.96); opacity: 0.72; } to { transform: scale(1.06); opacity: 1; } }
    @keyframes walletHeroScanBob { from { transform: translateY(0) scaleX(1); } to { transform: translateY(-4px) scaleX(1.05); } }
    @media (max-width: 900px) { .wallet-hero-scan-status, .live-damage-report { width: calc(100% - 12px); max-width: none; } .live-damage-report-header { flex-direction: column; align-items: flex-start; } .live-damage-report-header-right { align-items: flex-start; } .live-damage-report-row { grid-template-columns: 22px minmax(0, 1fr) auto; gap: 6px; padding: 5px 7px; } }
  `;
